-- ─────────────────────────────────────────────────────────────────────────────
-- SECCIÓN 7: Registros de asistencia (9 miembros activos, semanal Ene–May 2026)
-- ─────────────────────────────────────────────────────────────────────────────

INSERT INTO gym_attendance_logs (id, org_id, user_id, check_in_at, check_out_at)
SELECT
  gen_random_uuid(),
  '00000000-0000-0000-0000-000000000001',
  member_id,
  series_date + INTERVAL '7 hours' + (random() * INTERVAL '4 hours'),
  series_date + INTERVAL '8 hours' + (random() * INTERVAL '3 hours')
FROM
  unnest(ARRAY[
    'de000001-0000-0000-0000-000000000000'::uuid,
    'de000002-0000-0000-0000-000000000000'::uuid,
    'de000004-0000-0000-0000-000000000000'::uuid,
    'de000005-0000-0000-0000-000000000000'::uuid,
    'de000006-0000-0000-0000-000000000000'::uuid,
    'de000007-0000-0000-0000-000000000000'::uuid,
    'de000008-0000-0000-0000-000000000000'::uuid,
    'de000009-0000-0000-0000-000000000000'::uuid,
    'de000010-0000-0000-0000-000000000000'::uuid
  ]) AS member_id
CROSS JOIN
  generate_series(
    '2026-01-05'::date,
    '2026-05-03'::date,
    '7 days'::interval
  ) AS series_date;

-- ─────────────────────────────────────────────────────────────────────────────
-- SECCIÓN 8: Verificación final
-- ─────────────────────────────────────────────────────────────────────────────

DO $$
DECLARE
  v_members  int;
  v_subs     int;
  v_proofs   int;
  v_expenses int;
  v_sales    int;
  v_attend   int;
BEGIN
  SELECT COUNT(*) INTO v_members  FROM profiles            WHERE org_id = '00000000-0000-0000-0000-000000000001' AND email LIKE '%demo@gymbase.dev';
  SELECT COUNT(*) INTO v_subs     FROM subscriptions       WHERE org_id = '00000000-0000-0000-0000-000000000001' AND id::text LIKE '5b0000%';
  SELECT COUNT(*) INTO v_proofs   FROM payment_proofs      WHERE org_id = '00000000-0000-0000-0000-000000000001' AND id::text LIKE 'pp0005%' AND status = 'approved';
  SELECT COUNT(*) INTO v_expenses FROM gym_expenses        WHERE org_id = '00000000-0000-0000-0000-000000000001' AND expense_date >= '2026-05-01';
  SELECT COUNT(*) INTO v_sales    FROM gym_sales           WHERE org_id = '00000000-0000-0000-0000-000000000001' AND created_at >= '2026-01-01';
  SELECT COUNT(*) INTO v_attend   FROM gym_attendance_logs WHERE org_id = '00000000-0000-0000-0000-000000000001' AND check_in_at >= '2026-01-01';

  RAISE NOTICE '=== DEMO SEED VERIFICACIÓN ===';
  RAISE NOTICE 'Miembros demo insertados:  %', v_members;
  RAISE NOTICE 'Suscripciones insertadas:  %', v_subs;
  RAISE NOTICE 'Pagos mayo aprobados:      %', v_proofs;
  RAISE NOTICE 'Gastos mayo insertados:    %', v_expenses;
  RAISE NOTICE 'Ventas totales (Ene-Abr):  %', v_sales;
  RAISE NOTICE 'Registros asistencia:      %', v_attend;
  RAISE NOTICE '==============================';
END $$;
